import {type FunctionComponent} from "react";
import {type IEditors} from "@lmb-it/kitsconcerto-types";


import {Skeleton} from "primereact/skeleton";
import SliderEditor from "./Editors/SliderEditor";
import TextEditor from "./Editors/TextEditor";
import MultiSelectEditor from "./Editors/MultiSelectEditor";
import ButtonsEditor from "./Editors/ButtonsEditor";
import DropdownEditor from "./Editors/DropdownEditor";
import TriStateEditor from "./Editors/TriStateEditor";
import PhoneEditor from "./Editors/PhoneEditor";
import DateEditor from "./Editors/DateEditor";
import {type ColumnEditorOptions} from "primereact/column";

export type EditorEl<T = any> = FunctionComponent<
  ColumnEditorOptions & T
>;

import DateRangeEditor from "./Editors/DateRangeEditor"; // ← ADD IMPORT

export const PickEditorElement: FunctionComponent<{
  Editor?: IEditors;
  isLoading: boolean;
  options: ColumnEditorOptions;
}> = ({ Editor, isLoading, options }) => {
  if (isLoading) {
    return <Skeleton className={"mb-2"} />;
  }

  if (Editor?.type == "multiSelect") {
    return <MultiSelectEditor list={Editor.list} {...options} />;
  } else if (Editor?.type == "buttons") {
    return (
        <ButtonsEditor
            list={Editor.list}
            isMultiple={Editor.isMultiple}
            {...options}
        />
    );
  } else if (Editor?.type == "dropdown") {
    return <DropdownEditor list={Editor.list} {...options} />;
  } else if (Editor?.type == "tristate") {
    return <TriStateEditor {...options} />;
  } else if (Editor?.type == "range" || Editor?.type == "number") {
    return (
        <SliderEditor
            min={Editor.min ?? 0}
            max={Editor.max ?? 100}
            {...options}
        />
    );
  } else if (Editor?.type == "phone") {
    return <PhoneEditor {...options} />;
  } else if (Editor?.type == "date") {
    if(Editor.isRanged){
      return <DateRangeEditor {...options} />;
    }else{
      return <DateEditor {...options} />;
    }

  } else if (Editor?.type == "text") {
    return <TextEditor {...options} />;
  } else {
    return null;
  }
};
